        new() { RecipeId = Recipes[0].RecipeId, RecipeInstructionId = Ulid.Parse("01KJ9R2AASPZQ21E7XJ3FW1XKS"), RecipeInstructionContent = "Start by cooking 12 oz. penne pasta according to the package directions (boil a large pot of water, add the pasta, and continue to boil until al dente). While the pasta is cooking, start the “alfredo” sauce. Mince two cloves of garlic and add them to a deep skillet or pot with 2 Tbsp butter. Sauté over medium heat for 1-2 minutes, or just until the garlic is soft and fragrant, but not brown.", RecipeInstructionIndex = 0, IsImage = false },
        new() { RecipeId = Recipes[0].RecipeId, RecipeInstructionId = Ulid.Parse("01KJ9R2AASCX1CH7QBW1WZJYP6"), RecipeInstructionContent = "https://www.budgetbytes.com/wp-content/uploads/2017/07/Add-Milk-to-Butter-and-Garlic.jpg", RecipeInstructionIndex = 1, IsImage = true },
        new() { RecipeId = Recipes[0].RecipeId, RecipeInstructionId = Ulid.Parse("01KJ9R2AASECGAM09CDB2HKG0N"), RecipeInstructionContent = "Add 2 cups of whole milk to the skillet and turn the heat down to medium-low.", RecipeInstructionIndex = 2, IsImage = false },
