        new() { RecipeId = Recipes[0].RecipeId, RecipeInstructionId = Ulid.Parse("01KJ9R2AASENZTTM1D81SBTKCN"), RecipeInstructionContent = "Also add 6 oz. cream cheese, cut into chunks. Heat and stir or whisk the milk and cheese until it is fully heated through and the cheese has melted into the milk. You’ll want to use a whisk once the cheese begins to melt.", RecipeInstructionIndex = 4, IsImage = false },
        new() { RecipeId = Recipes[0].RecipeId, RecipeInstructionId = Ulid.Parse("01KJ9R2AAT7VEHYS3RJACYSFJA"), RecipeInstructionContent = "https://www.budgetbytes.com/wp-content/uploads/2017/07/Add-Parmesan-to-Lighter-Spinach-Alfredo-Sauce.jpg", RecipeInstructionIndex = 5, IsImage = true },
        new() { RecipeId = Recipes[0].RecipeId, RecipeInstructionId = Ulid.Parse("01KJ9R2AATR0SP521V9PXE4YEX"), RecipeInstructionContent = "Whisk 3/4 cup grated Parmesan into the milk sauce. Continue to whisk while the mixture heats, allowing it to come up to a gentle simmer. When it reaches a simmer, the sauce will thicken. Once the Parmesan has fully melted in and the sauce has thickened, turn the heat down to low to keep the sauce warm. Season the sauce with 1/4 tsp salt and a generous amount of freshly cracked pepper.", RecipeInstructionIndex = 6, IsImage = false },
        new() { RecipeId = Recipes[0].RecipeId, RecipeInstructionId = Ulid.Parse("01KJ9R2AAT9087PPGY0YRDFDRF"), RecipeInstructionContent = "https://www.budgetbytes.com/wp-content/uploads/2017/07/Fresh-Baby-Spinach-for-Lighter-Spinach-Alfredo-Pasta.jpg", RecipeInstructionIndex = 7, IsImage = true },
        new() { RecipeId = Recipes[0].RecipeId, RecipeInstructionId = Ulid.Parse("01KJ9R2AATF3WZCA0962Y2HBC2"), RecipeInstructionContent = "Add the spinach: Now it’s time to add the spinach. I buy these huge bags of fresh spinach, which are the same amount as those large tubs you can buy, but it’s only $3.99 (the large tubs are usually more like $5.99). Anyway, add about 4 cups of spinach to the hot alfredo sauce…", RecipeInstructionIndex = 8, IsImage = false },
        new() { RecipeId = Recipes[0].RecipeId, RecipeInstructionId = Ulid.Parse("01KJ9R2AAT4F2W42VK2M9WXMX9"), RecipeInstructionContent = "https://www.budgetbytes.com/wp-content/uploads/2017/07/Wilted-Spinach-in-Sauce.jpg", RecipeInstructionIndex = 9, IsImage = true },
        new() { RecipeId = Recipes[0].RecipeId, RecipeInstructionId = Ulid.Parse("01KJ9R2AATFYR7BNG1TMHPABM4"), RecipeInstructionContent = "And stir it in until it has wilted and limp. This should only take a few minutes.", RecipeInstructionIndex = 10, IsImage = false },
